VALUES
  ('public-health-specialist-moex-00887', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '比較兩個已經有大規模社區感染的國家之COVID-19個案致死率是否有差，須注意兩國數據 在方法學上的可比較性。下列何者不屬於「方法學上的」可比較性？', '["兩國的個案定義", "兩國的疫苗普及率", "兩國的死因歸類方法", "兩國的篩檢與確診工具"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00888', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於匹配（matching），下列敘述何者正確？', '["匹配設計可增加研究統計效率", "匹配越多因子，越容易找到適合的對照組", "匹配設計只適用在病例對照研究中，世代研究不能使用匹配技術", "匹配設計的研究可更正確估計被匹配的干擾因子與疾病的相關性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00889', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關使用觀察性研究（observational study）評估衛生政策或醫療保健服務之成效，下列何者 正確？', '["前後對照研究（before-afterdesign）以單組研究對象自身為歷史對照組（historicalcontrols）， 不會受到長期變動（secularchange）的影響而造成偏差", "以服務使用者與非使用者兩組比較醫療保健服務之成效差異時，不會有選擇性偏差 （selectionbias）", "以現有的次級資料（secondarydata）進行觀察性研究，由於樣本數大以及資料完整，因此 幾乎不會有偏差出現", "以現有的次級資料（secondarydata）進行觀察性研究，可以採取前瞻性（prospective）或回 溯性（retrospective）研究法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00890', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某研究欲探討職業暴露與某疾病的關係，收案對象為在職員工。此研究的推論可能有什麼 問題？', '["暴露對疾病的相關性被低估", "暴露對疾病的相關性被高估", "相關性產生偏差，但方向無法預測", "難以判定時序性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00891', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某研究欲探討肥胖對A疾病的風險，若不分性別，則肥胖對A疾病的風險為2.2，依照性別 分層後，男性的風險為3，女性的風險為1.5。請問性別在此研究扮演什麼角色？', '["修飾因子（modifier）", "干擾因子（confounder）", "同時為修飾因子與干擾因子", "無法判定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00892', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於巢式（nested）病例對照研究的敘述，何者錯誤？', '["危險因子暴露與疾病相關的時序性比一般病例對照研究較明確", "需要在既有的世代研究或長期追蹤資料庫中才能執行此類研究設計", "病例與對照的招募可用發生率採樣或盛行率採樣的設計", "盛行率採樣設計比較能避免研究偏差"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00893', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '欲討論A、B因子暴露對某疾病發生的風險，整理族群不同暴露組合的發生率（單位：人/每 萬人年）如下，下列何者敘述正確？ A因子 暴露 未暴露 暴露 15.0 10.0 B因子 未暴露 3.0 2.0', '["A、B因子對某疾病的影響具加成協同作用", "A、B因子對某疾病的影響具加成拮抗作用", "A、B因子對某疾病的影響具累乘協同作用", "A、B因子對某疾病的影響具累乘拮抗作用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00894', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '新冠肺炎（COVID-19）全球疫情嚴重，臺灣2021年4到7月本土疫情傳播，防疫升級為三 級警戒，雖然疫苗不足，但透過積極的防疫措施後，疫情得到控制，降回二級警戒。請問對 疫情控制的敘述，何者正確？', '["COVID-19的基礎再生數（Basicreproductivenumber,R ）小於1 0", "疫情嚴重度降低時，有效再生數（Effectivereproductivenumber,R）大於1 e", "群體免疫是這波本土疫情獲得控制的重要原因", "COVID-19為我國第五類法定傳染病"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00895', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', 'COVID-19的篩檢方法包括核酸檢測（RT-PCR）與快篩，快篩檢驗速度快，30分鐘內就可獲 得篩檢結果，但準確度低於核酸檢測。請問下列敘述何者錯誤？', '["在低流行地區大規模快篩，將產生大量的偽陽性個案", "可以快篩搭配PCR平行檢定（testinparallel），提高特異度（specificity）", "抗原快篩可以找出受感染需被隔離的個案", "非流行期可透過抗體快篩，了解社區內的感染情形"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00896', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '探討疫苗應用在社區族群的影響程度，稱之什麼評估？', '["成效（efficacy）", "效果（effectiveness）", "修飾作用（modification）", "效率（efficiency）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00897', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列關於統合分析（meta-analysis）的敘述，何者正確？', '["無法應用在公共政策制定之參考", "等同於系統性回顧（systematicreview）", "常用來預估療效之成效值（effectsize）", "無法納入小樣本的研究"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
